'\n\tselect "column_name_sheet", "column_name_db"  from "name_maps"."column_names" cn \n\tjoin "name_maps"."table_names" tn on cn."table_id" = tn."table_id" \n\tjoin "name_maps"."schema_names" sn on tn."schema_id" = sn."schema_id"\n \twhere sn."schema_name" = \'uploaded_data\' and tn."table_name" = \'edna_wetlab_report\' \n  \tand cn."column_name_sheet" is not null;\n\t'
'\nselect "new_template_column_name", "column_name_db"  from "name_maps"."column_names" cn \njoin "name_maps"."table_names" tn on cn."table_id" = tn."table_id" \njoin "name_maps"."schema_names" sn on tn."schema_id" = sn."schema_id"\nwhere sn."schema_name" = \'uploaded_data\' and tn."table_name" = \'edna_wetlab_report\' \nand cn."in_template" in (\'both\', \'2\');\n'